# -*- coding: utf-8 -*-




def main():
    n = int(input())
    a = list(map(int, input().split()))
    max_len = 1
    l = 0
    for i in range(n):
        for j in range(i + 1, n + 1):
            if sum(a[i:j]) / (j - i) > sum(a[l:l + max_len]) / max_len:
                l = i
                max_len = j - i
    print(max_len)


if __name__ == '__main__':
    main()
